class Solution:
    def peopleAwareOfSecret(self, n, delay, forget):
        MOD = 10**9 + 7
        # f[d] = people who first learn on day d (1-indexed)
        f = [0] * (n + 1)
        f[1] = 1
        for d in range(1, n + 1):
            if f[d] == 0:
                continue
            # this group shares on days d+delay .. d+forget-1
            for share_day in range(d + delay, d + forget):
                if share_day <= n:
                    f[share_day] = (f[share_day] + f[d]) % MOD
        # at end of day n, those who learned on day d know it iff d > n - forget
        total = 0
        for d in range(1, n + 1):
            if d > n - forget:
                total = (total + f[d]) % MOD
        return total

