class Solution:
    def peopleAwareOfSecret(self, n, delay, forget):
        MOD = 10**9 + 7
        f = [0] * (n + 1)
        f[1] = 1
        window = 0
        for d in range(2, n + 1):
            # add those who become sharers today: learned on day d-delay
            if d - delay >= 1:
                window = (window + f[d - delay]) % MOD
            # remove those who forget today: learned on day d-forget
            if d - forget >= 1:
                window = (window - f[d - forget]) % MOD
            f[d] = window
        ans = 0
        for d in range(max(1, n - forget + 1), n + 1):
            ans = (ans + f[d]) % MOD
        return ans % MOD

