var peopleAwareOfSecret = function(n, delay, forget) {
    const MOD = 1000000007n;
    const f = new Array(n + 1).fill(0n);
    f[1] = 1n;
    let window = 0n;
    for (let d = 2; d <= n; d++) {
        if (d - delay >= 1) window = (window + f[d - delay]) % MOD;
        if (d - forget >= 1) window = (window - f[d - forget] + MOD) % MOD;
        f[d] = window;
    }
    let ans = 0n;
    for (let d = Math.max(1, n - forget + 1); d <= n; d++) {
        ans = (ans + f[d]) % MOD;
    }
    return Number(((ans % MOD) + MOD) % MOD);
};
